What does this program print?

```cpp
#include <iostream>

class Num {
    int m_val;
public:
    Num(int v) : m_val{ v } {}
    int get() const { return m_val; }
};

int doubled(const Num& n) { return n.get() * 2; }

int main() {
    std::cout << doubled(Num{ 7 }) << "\n";
    std::cout << Num{ 5 }.get() << "\n";
}
```

